{"content":"from __future__ import annotations

import asyncio
from collections.abc import Awaitable, Callable


async def run_tasks(
    tasks: list[Callable[[], Awaitable[None]]],
    max_concurrent: int,
) -> None:
    if max_concurrent <= 0:
        raise ValueError("max_concurrent must be greater than 0")

    iterator = iter(tasks)
    running: set[asyncio.Task[None]] = set()
    cancelling = False

    async def start_next() -> bool:
        nonlocal cancelling
        if cancelling:
            return False

        try:
            task_factory = next(iterator)
        except StopIteration:
            return False

        async def runner() -> None:
            await task_factory()

        running.add(asyncio.create_task(runner()))
        return True

    try:
        while len(running) < max_concurrent and await start_next():
            pass

        while running:
            done, pending = await asyncio.wait(
                running,
                return_when=asyncio.FIRST_COMPLETED,
            )
            running = set(pending)

            for task in done:
                task.result()

            while len(running) < max_concurrent and await start_next():
                pass
    except (asyncio.CancelledError, KeyboardInterrupt):
        cancelling = True

        for task in running:
            task.cancel()

        if running:
            await asyncio.gather(*running, return_exceptions=True)

        raise
